score = 10;
keepScoreBtn.click();
for (const element of scoreInputs) {
  assert.isFalse(element.checked);
  assert.isTrue(element.disabled);
}
for (const element of scoreSpans) {
  assert.strictEqual(element.innerText, "");
}

const messages = []
const oldAlert = alert;
alert = (msg) => {messages.push(msg)};
const oldWindow = window.alert;
window.alert = (msg) => {messages.push(msg)};
keepScoreBtn.click();
assert.lengthOf(messages, 1);
